-- article/eating-for-two-pregnancy-nutrition-myth
insert into public.content_posts (
  status, category, slug, title, description, excerpt, body, author,
  reading_time, tags, trimester, recipe, source, book_meta,
  published_at, updated_at
)
select
  'published',
  'article',
  'eating-for-two-pregnancy-nutrition-myth',
  'Eating for two? Why pregnancy nutrition isn''t about double portions',
  '“Eating for two” is a myth. Here''s what your body actually needs each trimester — calm, practical pregnancy nutrition without the pressure.',
  'The phrase sounds caring, but it leads to a lot of unnecessary worry. Here''s what real nourishment looks like, trimester by trimester.',
  '“You''re eating for two now!” is one of the first things many expecting mothers hear. It''s said with love — but it quietly suggests you should be eating twice as much. You don''t.

## How much extra do you really need?

For most of pregnancy, the extra energy your body needs is small — often nothing in the first trimester, and only a modest amount in the second and third. Think of it as a little more, not double.

- First trimester: usually no extra calories needed — focus on quality, not quantity.
- Second trimester: a small increase, roughly an extra snack a day.
- Third trimester: a little more again, as baby grows fastest.

## What actually matters

Nourishment matters far more than volume. Iron (palak, dal, gud), calcium (doodh, dahi, ragi, til), folate (leafy greens, citrus) and protein quietly do the heavy lifting. Small, frequent, warm meals are kinder on a queasy stomach than three large ones.

> Note: ParentVeda offers gentle, evidence-informed guidance — not medical advice. Always check with your doctor for decisions about your pregnancy.',
  'Team ParentVeda',
  '5 min read',
  ARRAY['nutrition', 'first trimester', 'weight']::text[],
  'first',
  NULL,
  NULL,
  NULL,
  '2026-05-12'::timestamptz,
  '2026-06-18'::timestamptz
where not exists (
  select 1 from public.content_posts
  where category = 'article' and slug = 'eating-for-two-pregnancy-nutrition-myth'
);

-- article/understanding-baby-movements-during-pregnancy
insert into public.content_posts (
  status, category, slug, title, description, excerpt, body, author,
